`timescale 1ns / 1ps

`include "uart_defines.vh"

module iob_uart16550_top (
   `include "iob_uart16550_top_io.vs"
);

   parameter uart_data_width = `UART_DATA_WIDTH;
   parameter uart_addr_width = `UART_ADDR_WIDTH;

   wire [                7:0] wb_dat8_i;  // 8-bit internal data input
   wire [                7:0] wb_dat8_o;  // 8-bit internal data output
   wire [               31:0] wb_dat32_o;  // debug interface 32-bit output
   // wire [                3:0] wb_sel_i;  // WISHBONE select signal
   wire [uart_addr_width-1:0] wb_adr_int;
   wire                       we_o;  // Write enable for registers
   wire                       re_o;  // Read enable for registers
   //
   // MODULE INSTANCES
   //

`ifdef DATA_BUS_WIDTH_8
`else
   // debug interface wires
   wire [                     3:0] ier;
   wire [                     3:0] iir;
   wire [                     1:0] fcr;
   wire [                     4:0] mcr;
   wire [                     7:0] lcr;
   wire [                     7:0] msr;
   wire [                     7:0] lsr;
   wire [`UART_FIFO_COUNTER_W-1:0] rf_count;
   wire [`UART_FIFO_COUNTER_W-1:0] tf_count;
   wire [                     2:0] tstate;
   wire [                     3:0] rstate;
`endif

`ifdef DATA_BUS_WIDTH_8
   ////  WISHBONE interface module
   uart_wb wb_interface (
      .clk       (clk_i),
      .wb_rst_i  (arst_i),
      .wb_dat_i  (wb_datout_i),
      .wb_dat_o  (wb_dat_o),
      .wb_dat8_i (wb_dat8_i),
      .wb_dat8_o (wb_dat8_o),
      .wb_dat32_o(32'b0),
      .wb_sel_i  (4'b0),
      .wb_we_i   (wb_we_i),
      .wb_stb_i  (wb_stb_i),
      .wb_cyc_i  (wb_cyc_i),
      .wb_ack_o  (wb_ack_o),
      .wb_adr_i  (wb_adr_i),
      .wb_adr_int(wb_adr_int),
      .we_o      (we_o),
      .re_o      (re_o)
   );
`else
   uart_wb wb_interface (
      .clk       (clk_i),
      .wb_rst_i  (arst_i),
      .wb_dat_i  (wb_datout_i),
      .wb_dat_o  (wb_dat_o),
      .wb_dat8_i (wb_dat8_i),
      .wb_dat8_o (wb_dat8_o),
      .wb_sel_i  (wb_sel_i),
      .wb_dat32_o(wb_dat32_o),
      .wb_we_i   (wb_we_i),
      .wb_stb_i  (wb_stb_i),
      .wb_cyc_i  (wb_cyc_i),
      .wb_ack_o  (wb_ack_o),
      .wb_adr_i  (wb_adr_i),
      .wb_adr_int(wb_adr_int),
      .we_o      (we_o),
      .re_o      (re_o)
   );
`endif

   // Registers
   uart_regs regs (
      .clk         (clk_i),
      .wb_rst_i    (arst_i),
      .wb_addr_i   (wb_adr_int),
      .wb_dat_i    (wb_dat8_i),
      .wb_dat_o    (wb_dat8_o),
      .wb_we_i     (we_o),
      .wb_re_i     (re_o),
      .modem_inputs({rs232_cts_i, rs232_dsr_i, rs232_ri_i, rs232_dcd_i}),
      .stx_pad_o   (rs232_txd_o),
      .srx_pad_i   (rs232_rxd_i),
`ifdef DATA_BUS_WIDTH_8
`else
      // debug interface signals    enabled
      .ier         (ier),
      .iir         (iir),
      .fcr         (fcr),
      .mcr         (mcr),
      .lcr         (lcr),
      .msr         (msr),
      .lsr         (lsr),
      .rf_count    (rf_count),
      .tf_count    (tf_count),
      .tstate      (tstate),
      .rstate      (rstate),
`endif
      .rts_pad_o   (rs232_rts_o),
      .dtr_pad_o   (rs232_dtr_o),
`ifdef UART_HAS_BAUDRATE_OUTPUT,
      .baud_o      (baud_o),
`endif
      .int_o       (int_o)

   );

`ifdef DATA_BUS_WIDTH_8
`else
   uart_debug_if dbg (  /*AUTOINST*/
      // Outputs
      .wb_dat32_o(wb_dat32_o[31:0]),
      // Inputs
      .wb_adr_i  (wb_adr_int[`UART_ADDR_WIDTH-1:0]),
      .ier       (ier[3:0]),
      .iir       (iir[3:0]),
      .fcr       (fcr[1:0]),
      .mcr       (mcr[4:0]),
      .lcr       (lcr[7:0]),
      .msr       (msr[7:0]),
      .lsr       (lsr[7:0]),
      .rf_count  (rf_count[`UART_FIFO_COUNTER_W-1:0]),
      .tf_count  (tf_count[`UART_FIFO_COUNTER_W-1:0]),
      .tstate    (tstate[2:0]),
      .rstate    (rstate[3:0])
   );
`endif

   initial begin
`ifdef DATA_BUS_WIDTH_8
      $display("(%m) UART INFO: Data bus width is 8. No Debug interface.");
`else
      $display("(%m) UART INFO: Data bus width is 32. Debug Interface present.");
`endif
`ifdef UART_HAS_BAUDRATE_OUTPUT
      $display("(%m) UART INFO: Has baudrate output");
`endif
   end

endmodule

